		t.Fatal("should be empty after clear")
	}
}

func TestBQ_Wraparound(t *testing.T) {
	q := NewBoundedQueue(3)
	q.Enqueue("a")
	q.Enqueue("b")
	q.Dequeue() // remove a
	q.Enqueue("c")
	q.Enqueue("d") // wraps around
	v, _ := q.Dequeue()
	if v != "b" {
